		stack = []

		for i in range(len(graph)):
			if not visited[i]:
				stack.append(i)
				visited[i] = True
				node = stack[-1]
				for neighbor, weight in graph[node]:
					if not visited[neighbor]:
						stack.append(neighbor)
						visited[neighbor] = True
					stack.pop()
				visited[node] = True
				stack.pop()
		for i in range(len(graph)):
			if not visited[i]:
				find_scc(graph, i)
		stack.append(s)
		visited = [False] * len(graph)
		while stack:
			node = stack.pop()
			for neighbor, weight in graph[node]:
				if not visited[neighbor] and weight > 0:
					visited[neighbor] = True
